/**
 * CYBERDUDEBIVASH — LIVE FEED WIDGET v3.0
 * ═══════════════════════════════════════════════════════════
 * Production-stable client-side live intel renderer.
 *
 * Source strategy (in priority order, zero CORS failures):
 *   1. /live-intel.json  — same-origin JSON generated by GitHub
 *      Actions every 30 min. No CORS. Always works.
 *   2. CISA KEV JSON     — public CDN, CORS-enabled, last 14 days
 *   3. Session cache     — stale data rather than empty widget
 *
 * Auto-refreshes every 10 minutes.
 *
 * © 2025 CYBERDUDEBIVASH. All rights reserved.
 * cyberdudebivash.com | Sentinel APEX Intelligence Platform
 * ═══════════════════════════════════════════════════════════
 */

(function () {
  'use strict';

  /* ─────────────────────────────────────────────
   * CONFIG
   * ───────────────────────────────────────────── */
  var CFG = {
    LOCAL_JSON:   '/live-intel.json',
    CISA_KEV:     'https://www.cisa.gov/sites/default/files/feeds/known_exploited_vulnerabilities.json',
    REFRESH_MS:   10 * 60 * 1000,   // 10 minutes
    MAX_CARDS:    12,
    CISA_LOOKBACK_DAYS: 21,
    CONTAINER_ID: 'live-intel-feed',
    CACHE_KEY:    'cbd_live_intel_v3',
    CACHE_TTL:    8 * 60 * 1000,    // 8 min cache
    DEBUG:        false
  };

  /* ─────────────────────────────────────────────
   * UTILITIES
   * ───────────────────────────────────────────── */
  function log() {
    if (CFG.DEBUG) console.log.apply(console, ['[LFW]'].concat(Array.prototype.slice.call(arguments)));
  }

  function timeAgo(dateStr) {
    if (!dateStr) return 'recently';
    var d = new Date(dateStr);
    var diff = Math.floor((Date.now() - d.getTime()) / 1000);
    if (diff < 60) return diff + 's ago';
    if (diff < 3600) return Math.floor(diff / 60) + 'm ago';
    if (diff < 86400) return Math.floor(diff / 3600) + 'h ago';
    if (diff < 86400 * 7) return Math.floor(diff / 86400) + 'd ago';
    return new Date(dateStr).toLocaleDateString([], { month: 'short', day: 'numeric' });
  }

  function escHtml(s) {
    if (!s) return '';
    return String(s)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  function slugify(s) {
    return String(s || '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
  }

  function getCache() {
    try {
      var raw = sessionStorage.getItem(CFG.CACHE_KEY);
      if (!raw) return null;
      var obj = JSON.parse(raw);
      if (Date.now() - obj.ts > CFG.CACHE_TTL) return null;
      return obj.data;
    } catch (e) { return null; }
  }

  function setCache(data) {
    try {
      sessionStorage.setItem(CFG.CACHE_KEY, JSON.stringify({ ts: Date.now(), data: data }));
    } catch (e) {}
  }

  /* ─────────────────────────────────────────────
   * THREAT CLASSIFICATION
   * ───────────────────────────────────────────── */
  var THREAT_PATTERNS = [
    { type: 'RCE',          label: 'Remote Code Execution', color: '#ff2d55',
      kw: ['remote code execution','arbitrary code','execute code','code execution',' rce ','rce.','(rce)'] },
    { type: 'LPE',          label: 'Privilege Escalation',  color: '#ff6b00',
      kw: ['privilege escalation','gain privilege','elevat','local privilege','escalate privilege'] },
    { type: 'AUTH_BYPASS',  label: 'Auth Bypass',           color: '#ff9500',
      kw: ['authentication bypass','bypass authentication','unauthenticated','improper authentication'] },
    { type: 'SQLI',         label: 'SQL Injection',         color: '#cc44ff',
      kw: ['sql injection','sqli'] },
    { type: 'UAF',          label: 'Use-After-Free',        color: '#ff4757',
      kw: ['use-after-free','use after free',' uaf '] },
    { type: 'OVERFLOW',     label: 'Buffer Overflow',       color: '#ff6348',
      kw: ['buffer overflow','stack overflow','heap overflow','out-of-bounds write','memory corruption'] },
    { type: 'SSRF',         label: 'SSRF',                  color: '#e056fd',
      kw: ['server-side request forgery','ssrf'] },
    { type: 'XSS',          label: 'XSS',                   color: '#2ed573',
      kw: ['cross-site scripting','xss'] },
    { type: 'ZERO_DAY',     label: 'Zero-Day',              color: '#ff0000',
      kw: ['zero-day','0-day','actively exploit','in the wild','zero day'] },
    { type: 'SUPPLY_CHAIN', label: 'Supply Chain',          color: '#ff6b81',
      kw: ['supply chain','malicious package'] }
  ];

  function classifyThreat(desc) {
    if (!desc) return { type: 'CVE', label: 'Vulnerability', color: '#00b4d8' };
    var d = (' ' + desc + ' ').toLowerCase();
    for (var i = 0; i < THREAT_PATTERNS.length; i++) {
      var p = THREAT_PATTERNS[i];
      for (var j = 0; j < p.kw.length; j++) {
        if (d.indexOf(p.kw[j]) !== -1) return { type: p.type, label: p.label, color: p.color };
      }
    }
    return { type: 'CVE', label: 'Vulnerability', color: '#00b4d8' };
  }

  function cvssColor(score) {
    var s = parseFloat(score);
    if (isNaN(s)) return { label: 'N/A', color: '#666' };
    if (s >= 9.0) return { label: 'CRITICAL', color: '#ff2d55' };
    if (s >= 7.0) return { label: 'HIGH',     color: '#ff6b00' };
    if (s >= 4.0) return { label: 'MEDIUM',   color: '#ffd700' };
    return              { label: 'LOW',       color: '#2ed573' };
  }

  /* ─────────────────────────────────────────────
   * SOURCE 1: /live-intel.json  (same-origin, GitHub Actions)
   * ───────────────────────────────────────────── */
  function fetchLocalJSON() {
    return new Promise(function (resolve) {
      var xhr = new XMLHttpRequest();
      xhr.timeout = 8000;
      xhr.open('GET', CFG.LOCAL_JSON + '?_=' + Math.floor(Date.now() / 60000));
      xhr.onreadystatechange = function () {
        if (xhr.readyState !== 4) return;
        if (xhr.status === 200) {
          try {
            var data = JSON.parse(xhr.responseText);
            // live-intel.json produced by fetch-live-intel.js
            // shape: { items: [...], generatedAt: ISO, totalPublished: N }
            if (Array.isArray(data.items) && data.items.length) {
              log('Local JSON: ' + data.items.length + ' items, generated ' + data.generatedAt);
              resolve(data.items);
            } else if (Array.isArray(data) && data.length) {
              resolve(data);
            } else {
              resolve(null); // empty / wrong shape → fall through
            }
          } catch (e) { log('Local JSON parse err:', e); resolve(null); }
        } else {
          // 404 = not yet generated (first deploy), that's expected
          log('Local JSON status:', xhr.status);
          resolve(null);
        }
      };
      xhr.onerror   = function () { log('Local JSON network err'); resolve(null); };
      xhr.ontimeout = function () { log('Local JSON timeout');     resolve(null); };
      xhr.send();
    });
  }

  /* ─────────────────────────────────────────────
   * SOURCE 2: CISA KEV  (CORS-enabled CDN)
   * Produces a normalised item array matching live-intel.json shape
   * ───────────────────────────────────────────── */
  function fetchCISAKEV() {
    return new Promise(function (resolve) {
      var xhr = new XMLHttpRequest();
      xhr.timeout = 12000;
      xhr.open('GET', CFG.CISA_KEV);
      xhr.onreadystatechange = function () {
        if (xhr.readyState !== 4) return;
        if (xhr.status === 200) {
          try {
            var data = JSON.parse(xhr.responseText);
            var cutoff = new Date(Date.now() - CFG.CISA_LOOKBACK_DAYS * 86400000);
            var items = (data.vulnerabilities || [])
              .filter(function (v) { return new Date(v.dateAdded) >= cutoff; })
              .map(function (v) {
                var threatType = classifyThreat(v.shortDescription || v.vulnerabilityName || '');
                return {
                  id:          v.cveID,
                  desc:        v.shortDescription || v.vulnerabilityName || '',
                  score:       null,
                  published:   v.dateAdded,
                  vendors:     [v.vendorProject || 'Unknown'],
                  product:     v.product || '',
                  dueDate:     v.dueDate || null,
                  source:      'CISA-KEV',
                  exploited:   true,
                  threatType:  threatType.type,
                  threatLabel: threatType.label,
                  threatColor: threatType.color
                };
              })
              .sort(function (a, b) { return new Date(b.published) - new Date(a.published); })
              .slice(0, CFG.MAX_CARDS);
            log('CISA KEV: ' + items.length + ' items');
            resolve(items.length ? items : null);
          } catch (e) { log('CISA parse err:', e); resolve(null); }
        } else {
          log('CISA status:', xhr.status); resolve(null);
        }
      };
      xhr.onerror   = function () { log('CISA network err'); resolve(null); };
      xhr.ontimeout = function () { log('CISA timeout');     resolve(null); };
      xhr.send();
    });
  }

  /* ─────────────────────────────────────────────
   * NORMALISE ITEM — ensure all expected fields exist
   * ───────────────────────────────────────────── */
  function normalise(item) {
    if (!item) return null;
    var desc = item.desc || item.description || item.shortDescription || '';
    var threat = (item.threatLabel && item.threatColor)
      ? { type: item.threatType || 'CVE', label: item.threatLabel, color: item.threatColor }
      : classifyThreat(desc);
    return {
      id:       item.id || item.cveID || '—',
      desc:     desc,
      score:    item.score != null ? item.score : null,
      published: item.published || item.dateAdded || null,
      vendors:  item.vendors || [item.vendor || item.vendorProject || 'Unknown'],
      product:  item.product || '',
      source:   item.source || 'SENTINEL',
      exploited: !!item.exploited,
      dueDate:  item.dueDate || null,
      refs:     item.refs || [],
      threat:   threat
    };
  }

  /* ─────────────────────────────────────────────
   * RENDER — SINGLE CARD
   * ───────────────────────────────────────────── */
  function renderCard(rawItem) {
    var item = normalise(rawItem);
    if (!item) return '';

    var threat  = item.threat;
    var sev     = cvssColor(item.score);
    var ago     = timeAgo(item.published);
    var vendor  = (item.vendors && item.vendors[0]) ? item.vendors[0] : (item.product || 'Unknown');
    var desc    = item.desc.length > 170 ? item.desc.substring(0, 167) + '…' : item.desc;
    var slug    = slugify(item.id + '-' + vendor);
    var postHref = '/posts/' + slug + '.html';

    var exploitBadge = item.exploited
      ? '<span class="lfw-badge lfw-exploit">⚡ EXPLOITED IN WILD</span>' : '';
    var cisaBadge = (item.source === 'CISA-KEV' || (item.source || '').indexOf('CISA') !== -1)
      ? '<span class="lfw-badge lfw-cisa">🛡 CISA KEV</span>' : '';
    var dueBadge = item.dueDate
      ? '<span class="lfw-badge lfw-due">⏰ Patch by ' + item.dueDate + '</span>' : '';
    var scoreBadge = item.score != null
      ? ('<span class="lfw-badge lfw-score" style="background:' + sev.color + '18;color:' + sev.color + ';border-color:' + sev.color + '40">'
          + 'CVSS ' + item.score + ' — ' + sev.label + '</span>')
      : '<span class="lfw-badge lfw-score" style="color:#555;border-color:#2a2a3e">NO SCORE YET</span>';

    return (
      '<article class="lfw-card' + (item.exploited ? ' lfw-card-hot' : '') + '" style="--tc:' + threat.color + '">' +
        '<div class="lfw-card-top">' +
          '<div class="lfw-tleft">' +
            '<span class="lfw-ttype" style="color:' + threat.color + ';border-color:' + threat.color + '44">' + escHtml(threat.label) + '</span>' +
            '<span class="lfw-src">' + escHtml(item.source) + '</span>' +
          '</div>' +
          '<time class="lfw-time">' + ago + '</time>' +
        '</div>' +
        '<div class="lfw-card-mid">' +
          '<h3 class="lfw-cve">' + escHtml(item.id) + '</h3>' +
          '<div class="lfw-vendor">🎯 ' + escHtml(vendor) + (item.product ? ' <span class="lfw-sep">·</span> ' + escHtml(item.product) : '') + '</div>' +
          (desc ? '<p class="lfw-desc">' + escHtml(desc) + '</p>' : '') +
          '<div class="lfw-badges">' + exploitBadge + cisaBadge + scoreBadge + dueBadge + '</div>' +
        '</div>' +
        '<div class="lfw-card-bot">' +
          '<a href="' + escHtml(postHref) + '" class="lfw-read">🔍 Full Intel Report →</a>' +
          (item.refs && item.refs[0]
            ? '<a href="' + escHtml(item.refs[0]) + '" class="lfw-ref" target="_blank" rel="noopener noreferrer">Source ↗</a>'
            : '') +
        '</div>' +
      '</article>'
    );
  }

  /* ─────────────────────────────────────────────
   * RENDER — WIDGET SHELL
   * ───────────────────────────────────────────── */
  function renderWidget(items, container, animate) {
    var exploitCount = items.filter(function (i) { return i.exploited; }).length;
    var critCount    = items.filter(function (i) { return parseFloat(i.score) >= 9.0; }).length;
    var timeStr      = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

    var cards = items.map(renderCard).join('');

    if (animate) {
      // Smooth grid swap without re-rendering header
      var grid = container.querySelector('.lfw-grid');
      if (grid) {
        grid.style.opacity = '0';
        grid.style.transition = 'opacity .3s';
        setTimeout(function () {
          grid.innerHTML = cards;
          grid.style.opacity = '1';
          // Update stats
          var stats = container.querySelectorAll('.lfw-stat-n');
          if (stats[0]) stats[0].textContent = exploitCount;
          if (stats[1]) stats[1].textContent = critCount;
          if (stats[2]) stats[2].textContent = items.length;
          var updated = container.querySelector('.lfw-updated');
          if (updated) updated.textContent = 'Updated ' + timeStr;
        }, 320);
        return;
      }
    }

    container.innerHTML = (
      '<div class="lfw-wrap">' +
        // ── HEADER ──
        '<div class="lfw-hdr">' +
          '<div class="lfw-hdr-top">' +
            '<div class="lfw-brand">' +
              '<span class="lfw-dot"></span>' +
              '<span class="lfw-brand-text">LIVE THREAT INTEL</span>' +
              '<span class="lfw-brand-sub">SENTINEL APEX</span>' +
            '</div>' +
            '<button class="lfw-refresh" id="lfw-refresh" title="Refresh intel feed" aria-label="Refresh">⟳</button>' +
          '</div>' +
          '<div class="lfw-hdr-stats">' +
            '<span class="lfw-stat"><span class="lfw-stat-n lfw-stat-exploit">' + exploitCount + '</span> Actively Exploited</span>' +
            '<span class="lfw-stat"><span class="lfw-stat-n lfw-stat-crit">' + critCount + '</span> Critical CVEs</span>' +
            '<span class="lfw-stat"><span class="lfw-stat-n lfw-stat-total">' + items.length + '</span> Live Threats</span>' +
            '<span class="lfw-stat lfw-updated">Updated ' + timeStr + '</span>' +
          '</div>' +
        '</div>' +
        // ── GRID ──
        '<div class="lfw-grid">' + cards + '</div>' +
        // ── FOOTER ──
        '<div class="lfw-ftr">' +
          '<span class="lfw-copy">© 2025 CYBERDUDEBIVASH · Sentinel APEX · cyberdudebivash.com</span>' +
          '<span class="lfw-auto">Auto-refreshes every 10 minutes</span>' +
        '</div>' +
      '</div>'
    );

    // Bind refresh button
    var btn = document.getElementById('lfw-refresh');
    if (btn) {
      btn.addEventListener('click', function () {
        btn.textContent = '⟳';
        btn.style.animation = 'lfwSpin .7s linear infinite';
        doFetch(container, true).then(function () {
          btn.style.animation = '';
        });
      });
    }
  }

  /* ─────────────────────────────────────────────
   * RENDER — SKELETON LOADING
   * ───────────────────────────────────────────── */
  function renderSkeleton(container) {
    var skels = '';
    for (var i = 0; i < 6; i++) {
      skels += '<div class="lfw-card lfw-skel">' +
        '<div class="lfw-sk s60"></div><div class="lfw-sk s80"></div>' +
        '<div class="lfw-sk s100"></div><div class="lfw-sk s70"></div>' +
      '</div>';
    }
    container.innerHTML = (
      '<div class="lfw-wrap">' +
        '<div class="lfw-hdr"><div class="lfw-hdr-top"><div class="lfw-brand">' +
          '<span class="lfw-dot lfw-dot-loading"></span>' +
          '<span class="lfw-brand-text">FETCHING LIVE INTEL…</span>' +
        '</div></div></div>' +
        '<div class="lfw-grid">' + skels + '</div>' +
      '</div>'
    );
  }

  /* ─────────────────────────────────────────────
   * RENDER — EMPTY / ERROR STATE
   * ───────────────────────────────────────────── */
  function renderEmpty(container, msg, retryFn) {
    container.innerHTML = (
      '<div class="lfw-wrap lfw-empty">' +
        '<div class="lfw-empty-icon">🛰</div>' +
        '<p class="lfw-empty-msg">' + escHtml(msg || 'Intel feed loading…') + '</p>' +
        '<button class="lfw-retry" id="lfw-retry">⟳ Refresh</button>' +
      '</div>'
    );
    var btn = document.getElementById('lfw-retry');
    if (btn && retryFn) btn.addEventListener('click', retryFn);
  }

  /* ─────────────────────────────────────────────
   * UPDATE SECTION LABEL TIMESTAMP
   * ───────────────────────────────────────────── */
  function updateLabel() {
    var lbl = document.getElementById('lfw-section-label-ts');
    if (lbl) {
      lbl.textContent = 'Last updated: ' + new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    }
  }

  /* ─────────────────────────────────────────────
   * FETCH ORCHESTRATOR
   * ───────────────────────────────────────────── */
  function doFetch(container, isRefresh) {
    // 1. Check session cache (skip on manual refresh)
    if (!isRefresh) {
      var cached = getCache();
      if (cached && cached.length) {
        log('Cache hit, ' + cached.length + ' items');
        renderWidget(cached, container, false);
        return Promise.resolve();
      }
      renderSkeleton(container);
    }

    // 2. Try local JSON first (same-origin, always works post-deploy)
    return fetchLocalJSON().then(function (localItems) {
      if (localItems && localItems.length) {
        setCache(localItems);
        renderWidget(localItems, container, isRefresh);
        updateLabel();
        return;
      }

      // 3. Fallback: CISA KEV
      log('Local JSON empty/missing — trying CISA KEV fallback');
      return fetchCISAKEV().then(function (cisaItems) {
        if (cisaItems && cisaItems.length) {
          setCache(cisaItems);
          renderWidget(cisaItems, container, isRefresh);
          updateLabel();
          return;
        }

        // 4. Last resort: use stale cache if available
        var stale = getCache();  // don't check TTL here
        if (stale && stale.length) {
          log('Using stale cache');
          renderWidget(stale, container, isRefresh);
          return;
        }

        // 5. Genuine empty state — first deploy, no data yet
        renderEmpty(
          container,
          'Live intel is warming up — GitHub Actions publishes new threats every 30 minutes. Check back shortly.',
          function () { doFetch(container, true); }
        );
      });
    }).catch(function (err) {
      log('Fetch pipeline error:', err);
      var cached = getCache();
      if (cached && cached.length) {
        renderWidget(cached, container, isRefresh);
      } else {
        renderEmpty(container, 'Intel fetch failed. Retrying automatically.', function () { doFetch(container, true); });
      }
    });
  }

  /* ─────────────────────────────────────────────
   * INJECT CSS STYLES (self-contained)
   * ───────────────────────────────────────────── */
  function injectStyles() {
    if (document.getElementById('lfw-css')) return;
    var css = [
      /* ── Wrapper ── */
      '.lfw-wrap{background:#09090f;border:1px solid #16213e;border-radius:14px;overflow:hidden;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif;margin:0 0 32px}',
      /* ── Header ── */
      '.lfw-hdr{background:linear-gradient(135deg,#0c0c1a,#091428);border-bottom:1px solid #16213e;padding:16px 20px 12px}',
      '.lfw-hdr-top{display:flex;align-items:center;justify-content:space-between;margin-bottom:10px}',
      '.lfw-brand{display:flex;align-items:center;gap:10px;flex-wrap:wrap}',
      '.lfw-dot{width:10px;height:10px;border-radius:50%;background:#ff2d55;box-shadow:0 0 8px #ff2d55;animation:lfwPulse 2s ease-in-out infinite;flex-shrink:0}',
      '.lfw-dot-loading{background:#ffd700;box-shadow:0 0 8px #ffd700;animation:lfwPulse .8s ease-in-out infinite}',
      '@keyframes lfwPulse{0%,100%{opacity:1;transform:scale(1)}50%{opacity:.4;transform:scale(.85)}}',
      '@keyframes lfwSpin{to{transform:rotate(360deg)}}',
      '.lfw-brand-text{font-size:13px;font-weight:700;letter-spacing:2px;color:#fff;text-transform:uppercase}',
      '.lfw-brand-sub{font-size:10px;font-weight:600;letter-spacing:1.5px;color:#00b4d8;text-transform:uppercase;padding:2px 7px;border:1px solid #00b4d830;border-radius:4px}',
      '.lfw-hdr-stats{display:flex;align-items:center;gap:14px;flex-wrap:wrap}',
      '.lfw-stat{font-size:11px;color:#666;letter-spacing:.5px}',
      '.lfw-stat-n{font-weight:800}',
      '.lfw-stat-exploit{color:#ff2d55}',
      '.lfw-stat-crit{color:#ff6b00}',
      '.lfw-stat-total{color:#00b4d8}',
      '.lfw-updated{margin-left:auto;color:#444;font-size:10px}',
      '.lfw-refresh{background:#ffffff0d;border:1px solid #ffffff18;color:#888;font-size:16px;line-height:1;border-radius:6px;padding:5px 9px;cursor:pointer;transition:all .2s;min-height:auto}',
      '.lfw-refresh:hover{background:#ffffff1a;color:#fff}',
      /* ── Card grid ── */
      '.lfw-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:1px;background:#16213e;transition:opacity .3s}',
      '@media(max-width:767px){.lfw-grid{grid-template-columns:1fr}}',
      /* ── Individual card ── */
      '.lfw-card{background:#0c0c18;padding:16px;border-left:3px solid var(--tc,#00b4d8);transition:background .2s;position:relative}',
      '.lfw-card:hover{background:#10101f}',
      '.lfw-card-hot{background:#100808}',
      '.lfw-card-hot:hover{background:#140a0a}',
      '.lfw-card-top{display:flex;align-items:center;justify-content:space-between;margin-bottom:10px}',
      '.lfw-tleft{display:flex;align-items:center;gap:8px;flex-wrap:wrap}',
      '.lfw-ttype{font-size:9px;font-weight:800;letter-spacing:1px;text-transform:uppercase;padding:2px 7px;border-radius:4px;border:1px solid}',
      '.lfw-src{font-size:9px;color:#444;letter-spacing:.5px;text-transform:uppercase}',
      '.lfw-time{font-size:10px;color:#444;white-space:nowrap}',
      '.lfw-card-mid{margin-bottom:12px}',
      '.lfw-cve{font-size:15px;font-weight:800;color:#fff;font-family:"SF Mono","Fira Code",monospace;margin:0 0 4px;letter-spacing:.5px}',
      '.lfw-vendor{font-size:11px;color:#00b4d8;margin-bottom:6px}',
      '.lfw-sep{color:#334;margin:0 2px}',
      '.lfw-desc{font-size:12px;color:#9aa;line-height:1.55;margin:0 0 10px}',
      '.lfw-badges{display:flex;flex-wrap:wrap;gap:4px}',
      '.lfw-badge{font-size:9px;font-weight:700;letter-spacing:.3px;text-transform:uppercase;padding:2px 7px;border-radius:4px;border:1px solid}',
      '.lfw-exploit{background:#ff2d5518;color:#ff2d55;border-color:#ff2d5540}',
      '.lfw-cisa{background:#ffd70018;color:#ffd700;border-color:#ffd70040}',
      '.lfw-due{background:#ff950018;color:#ff9500;border-color:#ff950040}',
      '.lfw-card-bot{display:flex;align-items:center;justify-content:space-between;padding-top:10px;border-top:1px solid #ffffff08}',
      '.lfw-read{font-size:11px;font-weight:700;color:#00b4d8;text-decoration:none;letter-spacing:.3px;transition:color .2s}',
      '.lfw-read:hover{color:#fff}',
      '.lfw-ref{font-size:10px;color:#444;text-decoration:none;transition:color .2s}',
      '.lfw-ref:hover{color:#888}',
      /* ── Skeleton ── */
      '.lfw-skel{pointer-events:none}',
      '.lfw-sk{border-radius:4px;margin-bottom:8px;height:13px;background:linear-gradient(90deg,#ffffff05 25%,#ffffff0e 50%,#ffffff05 75%);background-size:200% 100%;animation:lfwShimmer 1.6s infinite}',
      '@keyframes lfwShimmer{0%{background-position:200% 0}100%{background-position:-200% 0}}',
      '.s60{width:60%}.s70{width:70%}.s80{width:80%}.s100{width:100%}',
      /* ── Empty / error ── */
      '.lfw-empty{display:flex;flex-direction:column;align-items:center;justify-content:center;padding:52px 20px;gap:12px;background:#09090f}',
      '.lfw-empty-icon{font-size:36px;line-height:1}',
      '.lfw-empty-msg{font-size:13px;color:#666;text-align:center;max-width:380px;line-height:1.6}',
      '.lfw-retry{background:#ffffff0d;border:1px solid #ffffff18;color:#aaa;font-size:12px;padding:7px 18px;border-radius:8px;cursor:pointer;transition:all .2s;min-height:auto;margin-top:4px}',
      '.lfw-retry:hover{background:#ffffff1a;color:#fff}',
      /* ── Footer ── */
      '.lfw-ftr{display:flex;align-items:center;justify-content:space-between;padding:10px 20px;background:#07070d;border-top:1px solid #16213e;flex-wrap:wrap;gap:6px}',
      '.lfw-copy{font-size:10px;color:#2a2a3a;letter-spacing:.3px}',
      '.lfw-auto{font-size:10px;color:#222230}',
      /* ── Section label ── */
      '#lfw-section-label{display:flex;align-items:center;gap:10px;margin-bottom:14px}',
      '#lfw-section-label h2{font-size:13px;font-weight:800;letter-spacing:2.5px;text-transform:uppercase;color:#fff;margin:0}',
      '#lfw-section-label-ts{font-size:10px;color:#444;margin-left:auto}'
    ].join('\n');

    var style = document.createElement('style');
    style.id = 'lfw-css';
    style.textContent = css;
    document.head.appendChild(style);
  }

  /* ─────────────────────────────────────────────
   * INJECT SECTION LABEL
   * ───────────────────────────────────────────── */
  function injectLabel(container) {
    if (document.getElementById('lfw-section-label')) return;
    var label = document.createElement('div');
    label.id = 'lfw-section-label';
    label.innerHTML = '<h2>🛰 Live Breaking Intel</h2><span id="lfw-section-label-ts">Fetching…</span>';
    container.parentNode.insertBefore(label, container);
  }

  /* ─────────────────────────────────────────────
   * BOOT
   * ───────────────────────────────────────────── */
  function boot() {
    var container = document.getElementById(CFG.CONTAINER_ID);
    if (!container) {
      log('Container #' + CFG.CONTAINER_ID + ' not found');
      return;
    }
    injectStyles();
    injectLabel(container);

    // Initial load
    doFetch(container, false);

    // Auto-refresh every 10 minutes
    setInterval(function () {
      log('Auto-refresh');
      doFetch(container, true);
    }, CFG.REFRESH_MS);
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', boot);
  } else {
    setTimeout(boot, 600);
  }

  // Public API
  window.LIVE_FEED_WIDGET = {
    refresh: function () {
      var c = document.getElementById(CFG.CONTAINER_ID);
      if (c) doFetch(c, true);
    },
    cfg: CFG
  };

})();
